// ======================================
// BUSINESS RULE ENGINE
// PDC + ACTIVE HOLD = COMPLETELY REMOVED
// ONLY ELIGIBLE ROWS GO TO SWITCH
// ======================================

const invoice = $json;

const today = new Date("2026-07-13");
today.setHours(0, 0, 0, 0);

const dayName = today.toLocaleDateString("en-US", {
    weekday: "long"
});

const MS_PER_DAY = 86400000;


// ======================================
// SAFE DATE PARSER
// Supports:
// DD-MM-YYYY
// DD/MM/YYYY
// 15-Jun-2026
// ======================================

function parseDate(value) {

    if (!value) return null;

    const str = String(value).trim();

    // DD-MM-YYYY or DD/MM/YYYY
    const match = str.match(
        /^(\d{1,2})[-\/](\d{1,2})[-\/](\d{4})$/
    );

    if (match) {

        const day = Number(match[1]);
        const month = Number(match[2]) - 1;
        const year = Number(match[3]);

        const d = new Date(year, month, day);
        d.setHours(0, 0, 0, 0);

        return d;
    }

    // Other formats such as 15-Jun-2026
    const d = new Date(str);

    if (isNaN(d.getTime())) {
        return null;
    }

    d.setHours(0, 0, 0, 0);

    return d;
}


// ======================================
// PARSE DATES
// ======================================

const dueDate =
    parseDate(invoice["Due Date"]);

const holdTillDate =
    parseDate(invoice["Hold Till Date"]);

const hasPDC =
    String(invoice["PDC Date"] || "").trim() !== "";


// ======================================
// 1. REMOVE PDC ROWS COMPLETELY
// ======================================

if (hasPDC) {
    return null;
}


// ======================================
// 2. REMOVE ACTIVE HOLD ROWS COMPLETELY
// ======================================
// Example:
// Today = 11 July
// Hold Till = 15 July
// -> removed
//
// Today = 16 July
// Hold Till = 15 July
// -> allowed to continue
// ======================================

if (
    holdTillDate &&
    today <= holdTillDate
) {
    return null;
}


// ======================================
// 3. DUE DATE MUST EXIST
// ======================================

if (!dueDate) {
    return null;
}


// ======================================
// CALCULATE DAYS
// ======================================

const daysLeft = Math.round(
    (dueDate.getTime() - today.getTime()) /
    MS_PER_DAY
);

const daysOverdue =
    daysLeft < 0
        ? Math.abs(daysLeft)
        : 0;

invoice["Days Overdue"] = daysOverdue;


// ======================================
// DEFAULT ACTION
// ======================================

invoice["Action"] = "NONE";
invoice["Template Name"] = "";
invoice["Update Column"] = "";


// ======================================
// SWITCH ACTION RULES
// ======================================


// ---------- 3 DAYS BEFORE ----------

if (daysLeft === 3) {

    invoice["Action"] = "3_DAY";

    invoice["Template Name"] =
        "invoice_due_3_days";

    invoice["Update Column"] =
        "3 Days Before Reminder";
}


// ---------- 1 DAY AFTER DUE DATE ----------

else if (daysLeft === -1) {

    invoice["Action"] = "AFTER_1_DAY";

    invoice["Template Name"] =
        "invoice_due_after_1_day_v1";

    invoice["Update Column"] =
        "1 Day After Due Date Reminder";
}


// ---------- MONDAY CUSTOMER SUMMARY ----------

else if (
    daysLeft < 0 &&
    dayName === "Monday"
) {

    invoice["Action"] =
        "OVERDUE_MONDAY";
}


// ---------- TUE / THU / SAT SALESPERSON SUMMARY ----------

else if (
    daysLeft < 0 &&
    (
        dayName === "Tuesday" ||
        dayName === "Thursday" ||
        dayName === "Saturday"
    )
) {

    invoice["Action"] =
        "SALESPERSON_SUMMARY";
}


// ======================================
// COMMON FIELDS
// ======================================

invoice["Customer Name"] =
    invoice["Client Name"];

invoice["Customer WhatsApp"] =
    invoice["WhatsApp Number (Use This)"];

invoice["Salesperson Name"] =
    invoice["Sales Person Name"];

invoice["Salesperson WhatsApp"] =
    invoice["Sales Person Contact Number"];

invoice["Outstanding Amount"] =
    Number(
        invoice["Balance Outstanding (₹)"] || 0
    );


// ======================================
// FRIENDLY ALIASES
// ======================================

invoice.customerName =
    invoice["Customer Name"];

invoice.customerPhone =
    String(
        invoice["Customer WhatsApp"] || ""
    );

invoice.invoiceNumber =
    invoice["Invoice Number"];

invoice.amount =
    invoice["Outstanding Amount"];

invoice.dueDate =
    invoice["Due Date"];

invoice.salesPerson =
    invoice["Salesperson Name"];

invoice.salesPhone =
    String(
        invoice["Salesperson WhatsApp"] || ""
    );


// ======================================
// RETURN ONLY ELIGIBLE ROW
// ======================================

return {
    json: invoice
};

