const groups = {};

for (const item of $input.all()) {

  const row = item.json;

  const customer = row.customerName;

  if (!groups[customer]) {

    groups[customer] = {

      customerName: row.customerName,
      customerPhone: row.customerPhone,
      salesPerson: row.salesPerson,
      salesPhone: row.salesPhone,

      totalOutstanding: 0,
      invoices: []

    };

  }

  groups[customer].totalOutstanding += Number(row.amount);

  groups[customer].invoices.push(
      `${row.invoiceNumber} (${row["Days Overdue"]} days overdue)`
  );

}

return Object.values(groups).map(c => ({

  json: {

    templateName: "summary_customer",

    customerName: c.customerName,
    customerPhone: c.customerPhone,

    invoiceSummary: c.invoices.join(", "),

    totalOutstanding:
      c.totalOutstanding.toLocaleString("en-IN"),

    salesPerson: c.salesPerson,
    salesPhone: c.salesPhone

  }

}));

const salespersons = {};

for (const item of $input.all()) {

    const row = item.json;
    const sp = row.salesPerson;

    if (!salespersons[sp]) {
        salespersons[sp] = {
            salesPerson: row.salesPerson,
            salesPhone: row.salesPhone,
            customers: {},
            grandTotal: 0
        };
    }

    const customer = row.customerName;

    if (!salespersons[sp].customers[customer]) {
        salespersons[sp].customers[customer] = {
            totalAmount: 0,
            maxDaysOverdue: 0
        };
    }

    const amount = Number(row.amount || 0);
    const daysOverdue = Number(row["Days Overdue"] || 0);

    // Add all invoice amounts for this customer
    salespersons[sp].customers[customer].totalAmount += amount;

    // Keep highest overdue days for this customer
    salespersons[sp].customers[customer].maxDaysOverdue =
        Math.max(
            salespersons[sp].customers[customer].maxDaysOverdue,
            daysOverdue
        );

    // Salesperson grand total
    salespersons[sp].grandTotal += amount;
}


// ======================================
// CREATE FINAL OUTPUT
// ======================================

return Object.values(salespersons).map(sp => {

    const summary = Object.entries(sp.customers)
        .map(([customer, data]) => {

            const dayText =
                data.maxDaysOverdue === 1
                    ? "1 day overdue"
                    : `${data.maxDaysOverdue} days overdue`;

            return `${customer}: ₹${data.totalAmount.toLocaleString("en-IN")} (${dayText})`;

        })
        .join(", ");

    return {
        json: {
            templateName: "salesperson_collection_summary_v1",

            salesPerson: sp.salesPerson,
            salesPhone: sp.salesPhone,

            customerSummary: summary,

            grandTotal: sp.grandTotal.toLocaleString("en-IN")
        }
    };

});
